// Apply Normalization & Type Coercion
// This code applies the schema normalization from the AI agent

// Get the schema from the AI agent output
const schemaOutput = $('Schema Inference & Header Normalization').first().json;
const schema = schemaOutput.schema || schemaOutput;

// Get the raw CSV data
const csvData = $('Extract CSV Data').all();

// Helper function to coerce values based on detected type
function coerceValue(value, targetType, format = null) {
  if (value === null || value === undefined || value === '') {
    return null;
  }

  switch (targetType.toLowerCase()) {
    case 'number':
    case 'integer':
    case 'float':
    case 'decimal':
      // Remove currency symbols, commas, and other formatting
      const numStr = String(value).replace(/[$,€£¥]/g, '').trim();
      const num = parseFloat(numStr);
      return isNaN(num) ? null : num;

    case 'date':
    case 'datetime':
    case 'timestamp':
      // Try to parse date
      const date = new Date(value);
      return isNaN(date.getTime()) ? null : date.toISOString();

    case 'boolean':
      const lowerVal = String(value).toLowerCase().trim();
      if (['true', 'yes', '1', 'y', 't'].includes(lowerVal)) return true;
      if (['false', 'no', '0', 'n', 'f'].includes(lowerVal)) return false;
      return null;

    case 'string':
    case 'text':
    default:
      return String(value).trim();
  }
}

// Helper function to standardize units
function standardizeUnit(value, unit, targetUnit) {
  if (!value || !unit || !targetUnit) return value;

  const conversions = {
    // Length
    'ft_to_m': 0.3048,
    'in_to_cm': 2.54,
    'mi_to_km': 1.60934,
    // Weight
    'lb_to_kg': 0.453592,
    'oz_to_g': 28.3495,
    // Temperature
    'f_to_c': (f) => (f - 32) * 5/9,
    'c_to_f': (c) => (c * 9/5) + 32
  };

  const conversionKey = `${unit.toLowerCase()}_to_${targetUnit.toLowerCase()}`;
  const conversion = conversions[conversionKey];

  if (typeof conversion === 'function') {
    return conversion(value);
  } else if (typeof conversion === 'number') {
    return value * conversion;
  }

  return value;
}

// Apply normalization to each row
const normalizedData = csvData.map(item => {
  const originalData = item.json;
  const normalizedRow = {};

  // If schema has field mappings, apply them
  if (schema.fields && Array.isArray(schema.fields)) {
    schema.fields.forEach(field => {
      const originalName = field.originalName || field.name;
      const canonicalName = field.canonicalName || field.name;
      const dataType = field.type || 'string';
      const format = field.format;
      const unit = field.unit;
      const targetUnit = field.targetUnit;

      // Get the original value
      let value = originalData[originalName];

      // Coerce to target type
      value = coerceValue(value, dataType, format);

      // Standardize units if needed
      if (unit && targetUnit && value !== null) {
        value = standardizeUnit(value, unit, targetUnit);
      }

      // Set the normalized value with canonical name
      normalizedRow[canonicalName] = value;
    });
  } else {
    // If no schema mapping, just copy the data
    Object.assign(normalizedRow, originalData);
  }

  return { json: normalizedRow };
});

// Add metadata about the normalization
const output = normalizedData.map((item, index) => ({
  json: {
    ...item.json,
    _metadata: {
      rowNumber: index + 1,
      normalizedAt: new Date().toISOString(),
      schemaApplied: true
    }
  }
}));

return output;

// Validate Data Quality: Check type consistency, detect outliers, validate ranges
// Input: Normalized data from previous node
// Output: Clean data + error report

const items = $input.all();
const cleanData = [];
const errorReport = [];
let totalRows = 0;
let errorCount = 0;

// Get schema from previous node (if available)
const schema = items[0]?.json?.schema || {};
const normalizedData = items[0]?.json?.normalizedData || items.map(item => item.json);

// Helper function to detect data type
function detectType(value) {
  if (value === null || value === undefined || value === '') return 'null';
  if (!isNaN(value) && !isNaN(parseFloat(value))) return 'number';
  if (value === 'true' || value === 'false' || typeof value === 'boolean') return 'boolean';
  if (typeof value === 'string' && /^\d{4}-\d{2}-\d{2}/.test(value)) return 'date';
  return 'string';
}

// Helper function to detect outliers using IQR method
function detectOutliers(values) {
  const sorted = values.filter(v => !isNaN(v)).sort((a, b) => a - b);
  if (sorted.length < 4) return new Set();

  const q1Index = Math.floor(sorted.length * 0.25);
  const q3Index = Math.floor(sorted.length * 0.75);
  const q1 = sorted[q1Index];
  const q3 = sorted[q3Index];
  const iqr = q3 - q1;
  const lowerBound = q1 - 1.5 * iqr;
  const upperBound = q3 + 1.5 * iqr;

  return new Set(values.map((v, i) => (v < lowerBound || v > upperBound) ? i : null).filter(i => i !== null));
}

// Analyze each column for type consistency and outliers
const columnStats = {};
const columns = Object.keys(normalizedData[0] || {});

columns.forEach(col => {
  const values = normalizedData.map(row => row[col]);
  const types = values.map(v => detectType(v));
  const typeCounts = types.reduce((acc, type) => {
    acc[type] = (acc[type] || 0) + 1;
    return acc;
  }, {});

  const dominantType = Object.keys(typeCounts).reduce((a, b) => 
    typeCounts[a] > typeCounts[b] ? a : b
  );

  columnStats[col] = {
    dominantType,
    typeCounts,
    outlierIndices: dominantType === 'number' ? 
      detectOutliers(values.map(v => parseFloat(v))) : new Set()
  };
});

// Validate each row
normalizedData.forEach((row, rowIndex) => {
  totalRows++;
  const rowErrors = [];

  columns.forEach(col => {
    const value = row[col];
    const stats = columnStats[col];
    const actualType = detectType(value);

    // Check type consistency
    if (actualType !== stats.dominantType && actualType !== 'null') {
      rowErrors.push({
        column: col,
        issue: 'type_mismatch',
        expected: stats.dominantType,
        actual: actualType,
        value: value
      });
    }

    // Check for outliers
    if (stats.outlierIndices.has(rowIndex)) {
      rowErrors.push({
        column: col,
        issue: 'outlier',
        value: value,
        message: 'Value is statistical outlier'
      });
    }

    // Check for empty required fields (assuming non-null is required)
    if ((value === null || value === undefined || value === '') && stats.typeCounts.null < totalRows * 0.5) {
      rowErrors.push({
        column: col,
        issue: 'missing_value',
        message: 'Required field is empty'
      });
    }
  });

  // Add to appropriate output
  if (rowErrors.length > 0) {
    errorCount++;
    errorReport.push({
      rowIndex: rowIndex + 1,
      data: row,
      errors: rowErrors,
      errorCount: rowErrors.length
    });
  } else {
    cleanData.push(row);
  }
});

// Calculate error rate
const errorRate = totalRows > 0 ? (errorCount / totalRows * 100).toFixed(2) : 0;

// Return results
return [
  {
    json: {
      summary: {
        totalRows,
        cleanRows: cleanData.length,
        errorRows: errorCount,
        errorRate: `${errorRate}%`,
        timestamp: new Date().toISOString()
      },
      columnStats,
      cleanData,
      errorReport,
      schema
    }
  }
];

